module top_module(
    input  A1,
    input  A2,
    input  A3,
    input  B1,
    output X
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // Logic to produce output signal X
    assign X = (A1 & ~A2) ? 1'b1 : (A2 & ~A1) ? 1'b0 : (A1 & A2 & A3) ? 1'b1 : (A1 == A2) ? B1 : 1'bx;

  always @(*) begin
    if (1'b0) begin
      X <= 1'b0;
      if (A1 == A2) begin
        X <= B1;
      end else if (A1 & ~A2) begin
        X <= 1'b1;
      end else if (A2 & ~A1) begin
        X <= 1'b0;
      end else if (A1 & A2 & A3) begin
        X <= 1'b1;
      end else begin
        X <= 1'bx;
      end;
    end
  end

endmodule

